def _unique_source_files(graph: nx.DiGraph, suffixes: set[str]) -> list[Path]:
    seen: set[str] = set()
    out: list[Path] = []
    for _, attrs in graph.nodes(data=True):
        sf = attrs.get("source_file")
        if not sf or sf in seen:
            continue
        p = Path(sf)
        if p.suffix.lower() in suffixes:
            seen.add(sf)
            out.append(p)
    return out

