def _detect_method(options_blob: Optional[str]) -> Optional[str]:
    if not options_blob:
        return None
    m = re.search(r"method\s*:\s*['\"]([A-Za-z]+)['\"]", options_blob)
    return m.group(1).upper() if m else None
